var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"직할 도시 로터스, 제5 격납고","JPN":"直轄都市ロータス、第5格納庫","ENG":"Direct Control City, Lotus, Hangar 5","TWN":"直轄城市洛德斯，第5機庫"},"stage":{"bg":"BLACK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 4.7","JPN":"CSE Lv.4.7","ENG":"CSE Lv. 4.7","TWN":"CSE Lv. 4.7"},"stage":{"bg":"BLACK","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"후… 쓰러뜨려도 끝없이 밀려드는 그림자라니.","JPN":"ふう……倒しても倒してもシャドウが迫ってくる。","ENG":"Huu... Shadows that keep coming no matter how many I drop.","TWN":"呼……就算擊倒了，這些影子也無止盡湧上來。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"게다가 녀석들을 쓰러뜨려도 다른 그림자들이 시체를 가져가 재활용한다.","JPN":"それに、やつらを倒しても他のシャドウが死体を回収し、再利用する。","ENG":"And when one falls, the others haul off the body and reuse it.","TWN":"而且就算打倒牠們，其他影子還會拖走屍體再次利用。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"재조립… 이라고 했나?","JPN":"組み直し……と言ったか。","ENG":"\\"Reassembly\\"... was it?","TWN":"這該說是……再組裝？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"까다로운 상대로군.","JPN":"厄介な相手だ。","ENG":"What a troublesome foe.","TWN":"真是棘手的對手。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이런 소모전이 계속된다면 불리해지는 건 우리다.","JPN":"このまま消耗戦が続くとこっちが不利になる。","ENG":"If this war of attrition continues, the disadvantage will be ours.","TWN":"這種消耗戰再持續下去的話，吃虧的是我們。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 그림자들의 몸에 붙어있는 관리국 명찰…….","JPN":"あのシャドウたちが身につけている管理局の名札……","ENG":"Those Administration name tags on their bodies...","TWN":"那些影子身上掛著管理局的名牌……"},"stage":{"bg":"MAINSTREAM_124010","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저들에게 사로잡혀 재조립된 자들인가…….","JPN":"やつらに捕らわれて組み直された者たちか……","ENG":"Are they captives, reassembled by those things...?","TWN":"是被它們抓去再組裝的人嗎……"},"stage":{"bg":"MAINSTREAM_124010","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"여러분들의 노고와 희생은 잊지 않겠습니다.","JPN":"皆さんの献身と犠牲は忘れません。","ENG":"Your effort and sacrifice will not be forgotten.","TWN":"我不會忘記各位的辛勞與犧牲。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 역시, 여러분들과 같은 신세가 되더라도…….","JPN":"私も、たとえ皆さんと同じ姿になることになっても……","ENG":"Even if I end up like you...","TWN":"就算我變得和各位一樣……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"반드시 제가 지키고자 하는 걸 지켜낼 것입니다.","JPN":"自分が守りたいものを、必ず守り抜きます。","ENG":"I will still protect what I must protect.","TWN":"我也一定會守住我想守護的東西。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 적어도 지금은 아닙니다.","JPN":"ですが、少なくとも今はその時ではありません。","ENG":"But not today.","TWN":"但至少現在還不是時候。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이 많은 수를 전부 쓰러뜨릴 수 없다면…….","JPN":"この数を全部倒すことができないなら……","ENG":"If I cannot cut them all down...","TWN":"這麼龐大的數量如果無法全部擊倒……"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"내 능력을 최대한 끌어올려 이 주변을 모두 얼려서……!","JPN":"私の能力を最大限まで引き上げ、ここ一帯をすべて凍らせる……！","ENG":"I will push my power to the limit and freeze this entire area–!","TWN":"那我就把力量逼到極限，凍住這一帶……！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_IMPACT_ICE"},{"id":"L31_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_QM","text":{"KOREA":"아니. 그럴 필요는 없다.","JPN":"いや、その必要はない。","ENG":"No. There is no need.","TWN":"不，沒有這個必要。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_QM","text":{"KOREA":"네가 어둠 속에서도 포기하지 않고 나아가준 덕분에.","JPN":"君が闇の中でも諦めず前に進んでくれたおかげで。","ENG":"Because you kept moving forward without giving up in the dark,","TWN":"多虧你身處黑暗之中也沒有放棄，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_QM","text":{"KOREA":"우리가 늦지 않고 이곳에 올 수 있었으니까.","JPN":"間に合うことができた。","ENG":"we were able to arrive before it was too late.","TWN":"我們才能及時趕到這裡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"큭! 갑자기 바람이……?","JPN":"くっ！　急に風が……？","ENG":"Kgh! A sudden gust of wind...?","TWN":"呃！忽然起風了……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"격납고로 접근하던 그림자들을 전부 한곳으로 모았어요!","JPN":"格納庫辺りのシャドウを、全て1か所に集めました！","ENG":"I gathered every Shadow approaching the hangar into one spot!","TWN":"接近機庫的那些影子，全都集中到一處了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"지금입니다! 수리야 님!","JPN":"今です、スーリヤ様！","ENG":"Now, Surya!","TWN":"就是現在！蘇莉耶！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"불리한 전황에도 버텨준 당신에게 경의를 표한다.","JPN":"不利な戦況でも耐えてくれた君に敬意を払おう。","ENG":"I honor you for holding out in such dire conditions.","TWN":"即使在不利的戰況下仍堅守不退，我向你表以敬意。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이 뒤는 우리에게 맡기도록.","JPN":"あとは私たちに任せてくれ。","ENG":"Leave the rest to us.","TWN":"接下來的事就交給我們吧。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"바루나 전대의 수리야.","JPN":"ヴァルナ戦隊のスーリヤ。","ENG":"Surya of Varuna Division.","TWN":"伐樓拿戰隊的蘇莉耶。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"정화를 시작하겠다.","JPN":"浄化を始める。","ENG":"Commencing purification.","TWN":"現在開始進行淨化。"},"stage":{"bg":"VARUNA_02","bgm":"THEMA_CA_SURYA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};